var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"어휴...... 마지막 등교날까지 침식체나 상대하고 이게 무슨 난리야.","JPN":"ふう……なんてこった。\\n最後の登校日なのに侵食体なんかを相手にすることになるなんて。","ENG":"Gah! I can't believe I fought C.O. on my last day at school.","TWN":"哈……最後一天上學還要跟侵蝕體戰鬥，這也太衰了吧。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"후훗. 그래도 의외네.","JPN":"ふふっ。でも意外だったよ。","ENG":"Hah hah. But that was surprising.","TWN":"呵呵...真是個意外啊。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"엄청 거칠게 싸우면서도 고양이는 제대로 안 놓치던걸?","JPN":"あれだけ激しく戦ってても、絶対に猫を離さなかったでしょう？","ENG":"You didn't let go of the cat even as you fought tooth and nail.","TWN":"要是戰鬥再激烈一點，它們連貓也不會放過的吧？"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"거, 거기서 놓쳐 버리면 괜히 다칠지도 모르잖아!","JPN":"あ、あそこで離したら怪我するかもしれないだろ！","ENG":"I-I didn't want him to get hurt!","TWN":"那，那要是它們在哪裡遇上的話,貓會平白無故受傷的！"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"응, 응. 네 맘 알아. 원래 귀여운 동물은 보호본능을 자극한다잖아.","JPN":"うんうん、わかるよ。可愛い動物は庇護欲を刺激するって言うよね。","ENG":"Sure, sure. I understand. Cute animals stimulate our protective instinct.","TWN":"嗯...我懂了，原來可愛的動物會激發妳的保護欲啊。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"거기 태평하게 교문으로 들어오고 있는 둘, 그대로 멈춰라.","JPN":"そこ、のんきに校門から入ってきている二人。そのまま止まれ。","ENG":"You two, sauntering toward the gate as if you've got all the time in the world. Halt.","TWN":"喂，那邊，就是妳們！在那邊悠哉走進校門的兩個人，停下來。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"뭐야? 오늘도 지각한 사람 잡는 거였어?","JPN":"なんだ？　今日も遅刻したやつを捕まえるのか？","ENG":"Are you serious? You're going to catch us for tardiness, on our last day at school?","TWN":"這是幹嘛？今天在抓遲到的人嗎?"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"당연하지. 예외를 받아 주기 시작하면 규율이 허물어진다.","JPN":"当然だ。例外を認めてしまうと規律が崩れる。","ENG":"Absolutely. Making an exception is breaking the rules.","TWN":"當然，如果開始姑息例外，整個學校的紀律都會被打亂的。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"그리고 이 시간이 돼서야 등교하다니, 이건 명백한 지각이다.","JPN":"それに、今さら登校するとはな。これは明らかな遅刻だ。","ENG":"And last day or not, you're obviously late to school.","TWN":"再說，在這個時間才進校門，分明就是遲到。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"안녕, 선도부장~ 좋은 아침!","JPN":"やあ、風紀委員長～おはよう！","ENG":"Hey, Student Guide Leader. Good morning!","TWN":"先鋒部隊長~早上好！"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"하늘은 봤어? 오늘 하늘이 정말 푸르지 않니?","JPN":"空は見た？　本当に青くない？","ENG":"Did you see the sky? It's so blue and beautiful today, isn't it?","TWN":"妳看到天空了嗎？今天的天空很藍耶！"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"음?","JPN":"ん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"그러고 보니...... 이렇게 푸른 하늘은 오랜만이군.","JPN":"そういえば……こんなに青い空は久しぶりだな。","ENG":"Now that you mention it... I haven't seen such a blue sky for a long time.","TWN":"這樣說來...這麼藍的天空也是很久沒看到了。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"한동안 침식파 때문에 밤낮으로 칙칙한 잿빛만 펼쳐져 있었는데......","JPN":"しばらく侵食波のせいで、一日中くすんだ灰色だけが広がっていたのに……","ENG":"Lately, it's been gray all day because of the Corruption rays...","TWN":"這段時間由於受侵蝕波的影響，不論日夜，天空就只有昏暗的灰白色……"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"아니, 감상에 빠져 있을 때가 아니지.","JPN":"いや、感傷にふけっている場合じゃない。","ENG":"No, what am I talking about?","TWN":"不，現在不是沉浸在感傷中的時候。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"말 돌리지 마라. 얼렁뚱땅 넘어가려고 해도 소용없다.","JPN":"話を逸らすな。うやむやにしてごまかそうとしても無駄だぞ。","ENG":"Don't try to distract me. It doesn't work on me.","TWN":"別給我扯開話題！妳想瞞混過關也沒用。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"특히 서윤, 그대는 반장으로서 타의 모범이 되여야 할 입장임에도 각오가 부족하군.","JPN":"特にアオイ・シズカ。\\n君は学級委員長として他の模範になるべき立場なのに、覚悟が足りないな。","ENG":"Especially you, Seo Yoon. As a class president, you're not setting a good example for your classmates.","TWN":"特別是妳，徐芸！作為班長應該要做別人的榜樣，但是妳卻沒這個認知。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"교정에서의 마지막 날인지 아닌지는 중요하지 않다. 둘 다 엄하게......","JPN":"校舎での最後の日かどうかは重要じゃない。二人とも厳しく……","ENG":"It doesn't matter whether or not this is your last day at school. Both of you must be strictly—","TWN":"不管今天是不是妳們在校的最後一天，妳們兩個依舊都要嚴格地…"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};